json_tool = {
    "name": "output_json",
    "description": "Output the result as structured JSON",
    "input_schema": {
        "type": "object",
        "properties": {
            "name": {"type": "string"},
            "age": {"type": "integer"},
            "email": {"type": "string", "format": "email"}
        },
        "required": ["name", "age"]
    }
}

message = client.messages.create(
    model="claude-sonnet-4-20250514",
    max_tokens=1024,
    tools=[json_tool],
    tool_choice={"type": "tool", "name": "output_json"},
    messages=[{"role": "user", "content": "Extract: John Doe, 30, john@example.com"}]
)

tool_use = next(b for b in message.content if b.type == "tool_use")
data = tool_use.input  # {"name": "John Doe", "age": 30, "email": "john@example.com"}

extraction_tool = {
    "name": "extract_users",
    "description": "Extract user records from text",
    "input_schema": {
        "type": "object",
        "properties": {
            "users": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "name": {"type": "string"},
                        "role": {"type": "string"},
                        "skills": {"type": "array", "items": {"type": "string"}}
                    },
                    "required": ["name", "role"]
                }
            }
        },
        "required": ["users"]
    }
}

message = client.messages.create(
    model="claude-sonnet-4-20250514", max_tokens=2048,
    tools=[extraction_tool],
    tool_choice={"type": "tool", "name": "extract_users"},
    messages=[{"role": "user", "content": "Parse: John - Developer (Python, JS)\nSara - Designer (Figma)"}]
)
users = next(b for b in message.content if b.type == "tool_use").input["users"]
